## Name Normalization

Handle both Verse naming (device_campfire_device) and UE naming (Device_Campfire_C):

```rust
fn normalize_device_name(name: &str) -> String {
    // Device_Campfire_C -> device_campfire_device
    if name.starts_with("Device_") && name.ends_with("_C") {
        let base = &name[7..name.len()-2];
        format!("device_{}_device", base.to_lowercase())
    } else {
        name.to_lowercase()
    }
}
```

## Implementation

```rust
#[tool(description = "Get properties and events for a device type")]
async fn get_device_props(&self, device_type: String) -> Result<String, String> {
    let index = self.digest_index.read().await;
    let normalized = normalize_device_name(&device_type);

    let device = index.devices.get(&normalized)
        .ok_or_else(|| format!("Device not found: {}", device_type))?;

    let props = DeviceProperties {
        name: device.name.clone(),
        events: device.events.iter().map(format_event).collect(),
        methods: device.methods.iter().map(format_method).collect(),
        triggers: device.events.iter()
            .filter(|e| !e.name.starts_with("Receiver"))
            .map(|e| e.name.clone())
            .collect(),
        receivers: device.events.iter()
            .filter(|e| e.name.starts_with("Receiver") || e.name.ends_with("WhenReceiving"))
            .map(|e| e.name.clone())
            .collect(),
    };

    serde_json::to_string(&props).map_err(|e| e.to_string())
}
```

