## Task

Compare digest versions to detect breaking API changes.

## Use Case

When UEFN updates, the digest changes. This tool helps identify:
- Removed methods/events
- Changed signatures
- Deprecated devices

## Implementation

```rust
pub struct DigestDiffer;

impl DigestDiffer {
    pub fn diff(old: &DigestIndex, new: &DigestIndex) -> Vec<Change> {
        let mut changes = vec![];

        // Removed devices
        for device_name in old.devices.keys() {
            if !new.devices.contains_key(device_name) {
                changes.push(Change::DeviceRemoved(device_name.clone()));
            }
        }

        // Removed events
        for (name, old_device) in &old.devices {
            if let Some(new_device) = new.devices.get(name) {
                for event in &old_device.events {
                    if !new_device.events.iter().any(|e| e.name == event.name) {
                        changes.push(Change::EventRemoved {
                            device: name.clone(),
                            event: event.name.clone(),
                        });
                    }
                }
            }
        }

        // Changed signatures
        for (name, old_device) in &old.devices {
            if let Some(new_device) = new.devices.get(name) {
                for old_method in &old_device.methods {
                    if let Some(new_method) = new_device.methods.iter()
                        .find(|m| m.name == old_method.name)
                    {
                        if old_method.signature() != new_method.signature() {
                            changes.push(Change::SignatureChanged {
                                device: name.clone(),
                                method: old_method.name.clone(),
                                old: old_method.signature(),
                                new: new_method.signature(),
                            });
                        }
                    }
                }
            }
        }

        changes
    }
}

#[derive(Debug)]
pub enum Change {
    DeviceRemoved(String),
    EventRemoved { device: String, event: String },
    MethodRemoved { device: String, method: String },
    SignatureChanged { device: String, method: String, old: String, new: String },
}
```

