## Task

Detect wiring issues in device connections.

## Issues to Detect

1. **Orphaned channels**: Channels referenced by only one device
2. **Conflicts**: Multiple devices triggering same channel
3. **Missing connections**: Trigger with no receiver
4. **Cycles**: A → B → C → A chains

## Implementation

```rust
pub struct WiringValidator;

impl WiringValidator {
    pub fn validate(devices: &[DeviceInfo]) -> Vec<WiringIssue> {
        let mut issues = vec\![];

        // Build channel graph
        let mut senders: HashMap<String, Vec<&DeviceInfo>> = HashMap::new();
        let mut receivers: HashMap<String, Vec<&DeviceInfo>> = HashMap::new();

        for device in devices {
            // Extract channel assignments from settings
            for (key, value) in device.settings.iter().flatten() {
                if key.ends_with("Channel") {
                    senders.entry(value.clone()).or_default().push(device);
                }
                if key.ends_with("WhenReceiving") {
                    receivers.entry(value.clone()).or_default().push(device);
                }
            }
        }

        // Find orphaned channels
        for (channel, sender_list) in &senders {
            if \!receivers.contains_key(channel) {
                issues.push(WiringIssue {
                    kind: IssueKind::OrphanedChannel,
                    channel: channel.clone(),
                    devices: sender_list.iter().map(|d| d.label.clone()).collect(),
                    message: format\!("Channel '{}' has no receivers", channel),
                });
            }
        }

        // Find conflicts
        for (channel, sender_list) in &senders {
            if sender_list.len() > 1 {
                issues.push(WiringIssue {
                    kind: IssueKind::ChannelConflict,
                    channel: channel.clone(),
                    devices: sender_list.iter().map(|d| d.label.clone()).collect(),
                    message: format\!("Multiple devices send on channel '{}'", channel),
                });
            }
        }

        issues
    }
}
```

