#[tool(description = "Search Fortnite.digest.verse for symbols")]
async fn query_digest(
    &self,
    query: String,
    search_type: Option<String>,
) -> Result<String, String> {
    let index = self.digest_index.read().await;
    let search_type = search_type.unwrap_or("all".to_string());

    let results = match search_type.as_str() {
        "device" => index.search_devices(&query),
        "event" => index.search_events(&query),
        "method" => index.search_methods(&query),
        _ => index.search_all(&query),
    };

    serde_json::to_string(&results).map_err(|e| e.to_string())
}

impl DigestIndex {
    pub fn search_devices(&self, query: &str) -> Vec<SearchResult> {
        self.devices.values()
            .filter(|d| d.name.contains(query))
            .map(|d| SearchResult {
                kind: "device".to_string(),
                name: d.name.clone(),
                signature: format_device(d),
            })
            .collect()
    }

    pub fn search_events(&self, query: &str) -> Vec<SearchResult> {
        self.devices.values()
            .flat_map(|d| {
                d.events.iter()
                    .filter(|e| e.name.contains(query))
                    .map(|e| SearchResult {
                        kind: "event".to_string(),
                        name: e.name.clone(),
                        device: Some(d.name.clone()),
                        signature: format_event(e),
                    })
            })
            .collect()
    }
}
