## Caching Strategy

Use mtime-based caching to avoid re-scanning on every request:

```rust
use std::time::SystemTime;
use std::collections::HashMap;

struct ScanCache {
    project_path: PathBuf,
    last_scan: Option<ScanResult>,
    last_mtime: Option<SystemTime>,
}

impl ScanCache {
    fn needs_refresh(&self) -> bool {
        // Check if any .uasset file is newer than cache
        let current_mtime = get_max_mtime(&self.project_path);
        current_mtime > self.last_mtime
    }

    fn get_or_scan(&mut self, force: bool) -> Result<&ScanResult> {
        if force || self.needs_refresh() {
            self.last_scan = Some(scan_project(&self.project_path)?);
            self.last_mtime = Some(get_max_mtime(&self.project_path));
        }
        Ok(self.last_scan.as_ref().unwrap())
    }
}
