## Implementation

```rust
use walkdir::WalkDir;
use rayon::prelude::*;

pub fn scan_project(project_path: &Path) -> Result<ScanOutput> {
    let actors_path = project_path.join("Content/__ExternalActors__");
    ensure!(actors_path.exists(), "__ExternalActors__ not found");

    // Collect all .uasset files
    let files: Vec<PathBuf> = WalkDir::new(&actors_path)
        .follow_links(false)
        .into_iter()
        .filter_map(|e| e.ok())
        .filter(|e| e.path().extension().map(|ext| ext == "uasset").unwrap_or(false))
        .map(|e| e.path().to_path_buf())
        .collect();

    let total_files = files.len();

    // Parse in parallel
    let (devices, skipped): (Vec<_>, Vec<_>) = files
        .into_par_iter()
        .map(|path| parse_file(&path, &actors_path))
        .partition(Result::is_ok);

    let devices: Vec<DeviceInfo> = devices.into_iter().map(Result::unwrap).collect();
    let skipped: Vec<String> = skipped.into_iter()
        .filter_map(|e| e.unwrap_err().downcast::<ScanError>().ok())
        .map(|e| e.file)
        .collect();

    // Group by type
    let mut by_type: IndexMap<String, Vec<DeviceInfo>> = IndexMap::new();
    for device in devices {
        by_type.entry(device.device_type.clone())
            .or_default()
            .push(device);
    }

    // Sort type keys alphabetically
    by_type.sort_keys();

    Ok(ScanOutput {
        scanned_at: chrono::Utc::now().to_rfc3339(),
        project_root: project_path.display().to_string(),
        total_files,
        total_devices: by_type.values().map(|v| v.len()).sum(),
        skipped: skipped.len(),
        device_types: by_type.keys().cloned().collect(),
        by_type,
    })
}

fn parse_file(path: &Path, actors_path: &Path) -> Result<DeviceInfo> {
    // 1. Open asset (try multiple engine versions)
    let asset = open_asset(path)?;

    // 2. Get name map and classify
    let names = asset.get_name_map();
    let classification = classify(&names);

    // 3. Extract properties
    let (label, settings) = extract_properties(&asset)?;

    // 4. Determine device type (fingerprint if needed)
    let device_type = classification.device_type
        .or_else(|| fingerprint_device(&settings))
        .unwrap_or_else(|| "Unknown".to_string());

    // 5. Skip if no useful data
    if device_type == "Unknown" 
        && classification.triggers.is_empty() 
        && settings.is_empty() 
    {
        bail!(ScanError::NoDeviceData { file: relative_path });
    }

    Ok(DeviceInfo {
        file: path.strip_prefix(actors_path)?.display().to_string(),
        device_type,
        label,
        triggers: classification.triggers.into_iter().unique().sorted().collect(),
        receivers: classification.receivers.into_iter().unique().sorted().collect(),
        settings: if settings.is_empty() { None } else { Some(settings) },
    })
}
